import{_ as s}from"./chunks/theme.V93572XQ.js";import{_ as r,a as e,M as i,f as l,o as p}from"./chunks/framework.BzjwFSRk.js";const o="/assets/F3fKll8xQk.D-OZ0HFG.jpg",n="/assets/4fdHWVvX-V0.DxYYC2B3.jpg",c="/assets/7kbR_HknwNw.DBpIHQIM.jpg",h="/assets/7RPW27C_yJw.BykxWVBB.jpg",m="/assets/7SmwvtRPyfc.D0nytZUQ.jpg",g="/assets/8VK3Pc_GyPg.Dfd2ZzFw.jpg",u="/assets/BTCUuCd4ibA.Bxffp2Qh.jpg",d="/assets/Dmigot9bAhQ.CoG17qX2.jpg",_="/assets/E7ioW4GVNSQ.BZZ5FCi5.jpg",b="/assets/G9tx3HkRfvQ.DcAvQJXc.jpg",f="/assets/H-9MHn4MiIw.tPat5QBJ.jpg",k="/assets/oNh0YcSf348.D-gmHeNX.jpg",q="/assets/oS1J3nKoXfs.B_JhK0RK.jpg",j="/assets/T2a0mLHVVqA.CmOcisN_.jpg",x="/assets/tRW2CrM9-RI.D7YVB1p0.jpg",v="/assets/vCngynSPVXY.Di-J7oJx.jpg",P="/assets/JOgpJigIgBM.VoWiyRnO.jpg",B="/assets/M6ItaKrYvtQ.BMwFjKB3.jpg",w="/assets/mUhbXqili2w.DHg4ms4l.jpg",J="/assets/Na94LpjuO-c.EiJ8iiQk.jpg",y="/assets/ndTfE16hpnc.WzvzsXnB.jpg",D="/assets/nR1djpaK8lY.DMjSxTJu.jpg",H="/assets/W5ELPvmnWgE.B42SXDAp.jpg",W="/assets/xYEe2fDQI0g.B1WHnOHL.jpg",C="/assets/zS0PSWx6oc0.yvfJJfJ6.jpg",I="/assets/zvrmFiYe8uI.BHrIH7Be.jpg",Q="/assets/BWTUnF0sKw.COcZzMjW.jpg",O=JSON.parse('{"title":"Ангар","description":"Общественные мастерские","frontmatter":{"title":"Ангар","description":"Общественные мастерские","date":"2020-10-20T00:00:00.000Z","icon":"logo.jpg","address":"Большая Монетная, 24АБ","place":"м. «Петроградская»","city":"г. Санкт-Петербург","tel":"+7 (911) 267-39-91","email":"allo@privetangar.ru","vk":"privetangar","facebook":"privetangar","instagram":"privetangar","telegram":"privetangar","coord":[59.96377436904135,30.32357894662327],"status":"open","cover":"cover.jpg","hours":"ежедневно с 10.00 до 22.00","youtube":"https://youtu.be/C7JRs8rjato"},"headers":[],"relativePath":"workshop/catalog/privetangar/index.md","filePath":"workshop/catalog/privetangar/index.md"}'),V={name:"workshop/catalog/privetangar/index.md"};function M(R,a,S,K,N,X){const t=s;return p(),e("div",null,[a[0]||(a[0]=i('<p><strong>Общественные мастерские</strong> — некоммерческое пространство для ручного труда на Петроградской стороне.</p><p>Под одной крышей объединены столярная, швейная и керамическая мастерские со всем необходимым оборудованием, мастерами-наставниками и резидентами.</p><p>У нас можно проходить курсы, посещать лекции и мастер-классы, а в свободные от занятий дни пользоваться возможностями Общественных мастерских в формате коворкинга.</p><p>Мы также сотрудничаем с благотворительными организациями. Проводим обучение, мастер-классы для сотрудников, волонтёров и подопечных, а ещё изготавливаем сувенирную продукцию.</p><p>Мы не забыли и о дружелюбной атмосфере и уютной кухне, где вы сможете выпить чай и обсудить свои творческие проекты. Все форматы бесплатные.</p><p>Общественные мастерские — это государственное бюджетное учреждение подростково-молодёжного центра «Петроградский», сектора молодежной политики и взаимодействия с общественными организациями Администрации Петроградского района.</p><h2 id="интенсивы-и-коворкинг" tabindex="-1">Интенсивы и коворкинг <a class="header-anchor" href="#интенсивы-и-коворкинг" aria-label="Permalink to &quot;Интенсивы и коворкинг&quot;">​</a></h2><p>В «Общественных мастерских» по будням проходят интенсивы в трёх мастерских: швейная, керамическая и столярная. По выходным дням доступен производственный коворкинг для самостоятельной работы (ремонта одежды, бытовой техники, реализации творческих проектов). Регулярно проводятся дополнительные мероприятия. Все форматы бесплатны для посещения.</p><h3 id="коворкинг" tabindex="-1">Коворкинг: <a class="header-anchor" href="#коворкинг" aria-label="Permalink to &quot;Коворкинг:&quot;">​</a></h3><ul><li>Производственный коворкинг доступен для всех людей старше 18 лет, которые умеют работать за оборудованием самостоятельно.</li><li>Время работы производственного коворкинга: 12:00-18:00 в пятницу, субботу и воскресенье. Забронировать место в коворкинге можно с помощью клавиши в шапке сообщества «Забронировать».</li><li>Для допуска в коворкинг необходимо посетить установочную встречу или закончить наш интенсив.</li><li>Установочные встречи необходимы для того, чтобы мастер убедился, что вы можете работать самостоятельно, и проводятся один раз в две недели по выходным в 10:30, длительность около 1 часа. Запись по ссылке: <a href="https://b24-f6usik.bitrix24.site/angar_kvrkng/" class="external-link" target="_blank" rel="noreferrer">https://b24-f6usik.bitrix24.site/angar_kvrkng/</a></li><li>Время работы за оборудованием, которое вы можете забронировать, составляет 4 часа в день и не более 20 часов в месяц. Время может быть продлено на месте по согласованию с мастером.</li><li>Материалы, расходники и личный инструменты для работы в коворкинге необходимо приносить свои.</li><li>Бронировать место в коворкинге можно не ранее чем за 2 недели.</li></ul><p>Интенсивы:</p><ul><li>Интенсивы доступны для людей от 18 до 35 лет.</li><li>Запись на следующий месяц проходит 20 числа текущего месяца: мы публикуем пост в группе во ВКонтакте со ссылкой на регистрацию.</li><li>Вы можете подавать несколько заявок сразу. Зачисляются те, кто раньше подали заявку, и ещё не посещали интенсивы в выбранной мастерской. Одновременно вы можете быть зачислены только на один интенсив.</li><li>На интенсивы в одной и той же мастерской вы можете быть зачислены не чаще 1 раза в 4 месяца.</li><li>Всем, кто прошел интенсив полностью, мастер дает доступ к бронированию производственного коворкинга по выходным для самостоятельной работы.</li></ul><p>Важно! Если Вы записались на интенсив или в коворкинг, но не пришли или отменили бронь меньше чем за сутки, мы очень не хотим, но имеем право ограничить Вам допуск в Общественные мастерские сроком до 6 месяцев.</p><h2 id="производственныи-коворкинг" tabindex="-1">Производственный коворкинг <a class="header-anchor" href="#производственныи-коворкинг" aria-label="Permalink to &quot;Производственный коворкинг&quot;">​</a></h2><p>Наше пространство открыто с 10:00 до 22:00 по субботам и воскресеньям для самостоятельной работы горожан.</p><p>Можно заниматься своим творческим проектом или отремонтировать любимую вещь!</p><p>🛠 Мы предоставляем доступ к оборудованию Мастерских, но вам понадобятся свои материалы.</p><p>✅ Посещение коворкинга по предварительной регистрации, с помощью которой вы бронируете себе время и оборудование.</p><p>👨‍🔧 В Мастерских всегда находится куратор или мастер, который поможет в базовых вопросах и проконтролирует соблюдение техники безопасности.</p><p>Самостоятельная работа подразумевает наличие необходимых знаний по использованию оборудования, также необходимо пройти инструктаж.</p><p><img src="'+o+'" alt=""><img src="'+n+'" alt=""><img src="'+c+'" alt=""><img src="'+h+'" alt=""><img src="'+m+'" alt=""><img src="'+g+'" alt=""></p><h3 id="кто-может-посещать-коворкинг" tabindex="-1">Кто может посещать коворкинг? <a class="header-anchor" href="#кто-может-посещать-коворкинг" aria-label="Permalink to &quot;Кто может посещать коворкинг?&quot;">​</a></h3><p>Производственный коворкинг подразумевает самостоятельную работу посетителей за оборудованием, поэтому доступ получают люди с опытом и навыками по выбранному направлению.</p><p>❗Важно: если опыта работы с оборудованием еще нет, то следует дождаться набора на подходящий вашему запросу интенсив - мы будем рады вас всему научить! После этого вы сможете посещать коворкинг.</p><h3 id="как-попасть-в-коворкинг" tabindex="-1">Как попасть в коворкинг? <a class="header-anchor" href="#как-попасть-в-коворкинг" aria-label="Permalink to &quot;Как попасть в коворкинг?&quot;">​</a></h3><p>Если у вас есть документы, подтверждающие прохождение обучения, опыт работы за оборудованием или вы уже прошли курс у нас, то для допуска в коворкинг вам достаточно посетить установочную встречу (регистрация также по ссылке в шапке профиля). После встречи у вас появится возможность зарегистрироваться в коворкинг на свободное время.</p><h3 id="установочные-встречи" tabindex="-1">Установочные встречи <a class="header-anchor" href="#установочные-встречи" aria-label="Permalink to &quot;Установочные встречи&quot;">​</a></h3><p>Наши установочные встречи, которые необходимо пройти перед посещением производственного коворкинга, продолжаются!</p><p>✨ На встречах вы сможете познакомиться с пространством, возможностями и техникой безопасности. Также сможете задать любые вопросы напрямую кураторам Мастерских.</p><p>Напоминаем, что встречи проводятся каждую неделю по выходным, ориентировочное время каждой встречи - полтора часа, количество участников - 8 человек.</p><p>❗ Установочные встречи - формат для людей с навыками по выбранному направлению. Если опыта нет совсем, то следует записаться на соответствующий интенсив при следующем наборе.</p><p><img src="'+u+'" alt=""><img src="'+d+'" alt=""><img src="'+_+'" alt=""><img src="'+b+'" alt=""><img src="'+f+'" alt=""></p>',32)),l(t,{link:"https://www.youtube.com/watch?v=McZIcChjsRU"}),a[1]||(a[1]=i('<h2 id="резиденция" tabindex="-1">Резиденция <a class="header-anchor" href="#резиденция" aria-label="Permalink to &quot;Резиденция&quot;">​</a></h2><h3 id="для-нко" tabindex="-1">Для НКО <a class="header-anchor" href="#для-нко" aria-label="Permalink to &quot;Для НКО&quot;">​</a></h3><p>Общественные мастерские «Гараж» совмещают в себе учебный центр, коворкинг, творческую резиденцию, а еще мы открыты для сотрудничества с НКО города в нашем пространстве.</p><p>Мы предлагаем для НКО:</p><ul><li>проведение групповых занятий для подопечных</li><li>организацию тимбилдингов для волонтёров и сотрудников</li><li>помощь в разработке и производстве сувенирной продукции от наших кураторов и резидентов</li></ul><p>Мы хотели бы помочь всем обратившимся НКО, но у нас есть ограничения по вместимости. Поэтому мы проводим отбор заявок от организаций для сотрудничества на ближайшие полгода.</p><p>В отборе приоритет будет отдан самым актуальным социально значимым и готовым к сотрудничеству проектам.</p><p>Напоминаем, что все наши форматы рассчитаны на людей от 18 лет. Если аудитория организации – дети и подростки, то необходимо присутствие сопровождающих с вашей стороны.</p><h3 id="для-начинающих-мастеров" tabindex="-1">Для начинающих мастеров <a class="header-anchor" href="#для-начинающих-мастеров" aria-label="Permalink to &quot;Для начинающих мастеров&quot;">​</a></h3><p>Резиденция даст новые возможности для участников: реализацию проекта или выведение его на новый уровень, а также принесет пользу нашему городу и НКО.</p><p>Кто может стать нашим резидентом:</p><ul><li>Авторы своих проектов в сфере дизайна и урбанистики</li><li>Создатели одежды, керамики, мебели, предметов интерьера</li><li>В приоритете проекты не старше года</li></ul><p>Что предоставляет резиденция:</p><ul><li>Бесплатный доступ к ресурсам мастерской: рабочему пространству, оборудованию, кухне и душевой.</li><li>Поддержку сообщества: бесплатные консультации и интенсивы от кураторов и мастеров.</li></ul><p>Чего мы ждем от резидентов взамен:</p><ul><li>Реализацию проектов для НКО и города Инициатором идеи можете быть вы или это будет ваш отклик на запрос города или конкретной НКО.</li><li>Соблюдения внутреннего распорядка и правил техники безопасности</li></ul><p><img src="'+k+'" alt=""><img src="'+q+'" alt=""><img src="'+j+'" alt=""><img src="'+x+'" alt=""><img src="'+v+'" alt=""></p>',17)),l(t,{link:"https://youtu.be/ztFb2IKov7s"}),a[2]||(a[2]=i('<h2 id="возможности" tabindex="-1">Возможности <a class="header-anchor" href="#возможности" aria-label="Permalink to &quot;Возможности&quot;">​</a></h2><h3 id="грязныи-блок" tabindex="-1">Грязный блок <a class="header-anchor" href="#грязныи-блок" aria-label="Permalink to &quot;Грязный блок&quot;">​</a></h3><p>При желании и обучении в «Гараже» вы сможете спроектировать и построить: мебель, детскую площадку, дом на дереве, формы для литья, купольный дом, лодку и многое другое.</p><p>Материалы, с которыми можно работать в «грязном» блоке:</p><ul><li>Мягкий листовой материал Фанера, оргстекло, ПВХ, ДСП, МДФ, ОСБ.</li><li>Дерево Массив мягких и твердых пород древесины.</li><li>Металл Тонкий листовой цветной металл, алюминий, некоторые виды стали.</li></ul><p>Мы предлагаем специальные «интенсивы» (краткосрочные курсы):</p><ul><li>Основы двухмерного и трехмерного моделирования</li><li>Основы управления станками с ЧПУ</li><li>Работа с ручным электроинструментом</li><li>Основы мебельного производства</li></ul><p>Насущные потребности, вроде ремонта собственной техники и гаджетов или печати деталей для своего проекта на трехмерном принтере — можно реализовывать в дни коворкинга: субботу и воскресенье.</p><h2 id="оборудование" tabindex="-1">Оборудование <a class="header-anchor" href="#оборудование" aria-label="Permalink to &quot;Оборудование&quot;">​</a></h2><h3 id="швеиная" tabindex="-1">Швейная <a class="header-anchor" href="#швеиная" aria-label="Permalink to &quot;Швейная&quot;">​</a></h3><ul><li>Четыре бытовые электронные швейные машины с множеством настроек и режимов, а также две прямострочные машинки с прямым приводом и электронными функциями.</li><li>Можно внести индивидуальные штрихи в свое изделие с помощью вышивальной машины. И мы имеем в виду не просто красивые стежки: вы можете загрузить свой рисунок и машинка его выполнит вышивкой.</li><li>Для капризного в работе трикотажа есть специальная распошивальная машинка.</li><li>Два полупрофессиональных оверлока для обработки краев и один профессиональный коверлок.</li><li>Коверлок - уникальная машина, сочетающая функционал оверлока и распошивальной машинки, будет очень полезна при создании одежды разной сложности.</li><li>Гладильный стол с вытяжкой, парогенератором и утюгом для отпаривания, глажки, заутюживания ткани и изделий.</li><li>При создании одежды всегда важно видеть как она будет выглядеть на человеке, моделировать. На плоды своих трудов приятно будет смотреть на манекенах: у нас четыре портновских и два дежурных женских.</li><li>Конечно, не только одежда может быть предметом на наших занятиях. У нас также есть инструменты для работы с кожей.</li></ul><p><img src="'+P+'" alt=""><img src="'+B+'" alt=""><img src="'+w+'" alt=""></p><h3 id="керамическая" tabindex="-1">Керамическая <a class="header-anchor" href="#керамическая" aria-label="Permalink to &quot;Керамическая&quot;">​</a></h3><p>В нашей керамической мастерской вы сможете создать свою чашку мечты, авторскую брошь, необычный предмет интерьера и многое другое. Что бы вы ни выбрали: вам предстоит пройти все этапы работы и для каждого из них в мастерской есть оборудование.</p><p>Ключевых позиций по одной, но они очень порадуют как новичков, так и профессиональных керамистов:</p><ul><li>Настольный раскатчик глины Для качественной раскатки глины нужно потратить время и приложить физические усилия. Этот инструмент может ускорить процесс, особенно при больших объемах материала.</li><li>Гончарный круг Знаем, что многие мечтают попробовать создавать керамику именно за кругом! Это и правда удивительный процесс: и трудоемкий, и медитативный одновременно.</li><li>Муфельная печь Вам откроется новое ощущение: тепло свежеиспеченной керамики и звук легкого потрескивания остывающих эмалей. Словом, зимним вечером разбирать готовые чашки особенно приятно!</li><li>Покрасочный шкаф С его помощью ваши изделия будут выглядеть более профессионально за счет равномерности цвета. Авторская роспись кистями, безусловно, прекрасна и вы можете выбрать этот способ.</li><li>Есть и наборы инструментов для работы с глиной за столом: всевозможные стеки и резаки.</li></ul><p><img src="'+J+'" alt=""><img src="'+y+'" alt=""><img src="'+D+'" alt=""></p><h3 id="грязныи-блок-1" tabindex="-1">Грязный блок <a class="header-anchor" href="#грязныи-блок-1" aria-label="Permalink to &quot;Грязный блок&quot;">​</a></h3><p>Сложно разделить «грязный» блок «Гаража» на конкретные мастерские. Технические возможности позволяют выполнять работы разного профиля: от ремонта велосипеда до конструирования робота.</p><p>Оборудование в этом блоке требует тщательного инструктажа и соблюдения техники безопасности, поэтому мы акцентируем внимание на этом в предварительном обучении.</p><h4 id="в-открытом-доступе" tabindex="-1">В открытом доступе: <a class="header-anchor" href="#в-открытом-доступе" aria-label="Permalink to &quot;В открытом доступе:&quot;">​</a></h4><ul><li>Трехмерный принтер</li><li>Производительные компьютеры для моделирования</li><li>Компрессор</li><li>Сварочный аппарат</li><li>Расширенный парк ручного электроинструмента</li><li>Оборудование для ремонта электроники</li></ul><h4 id="в-условно-открытом-доступе" tabindex="-1">В условно открытом доступе: <a class="header-anchor" href="#в-условно-открытом-доступе" aria-label="Permalink to &quot;В условно открытом доступе:&quot;">​</a></h4><ul><li>Два горизонтальных фрезерных стола с ЧПУ (широкий и средний формат)</li><li>Лазерный гравер с ЧПУ (средний формат)</li></ul><p>Условно открытый доступ подразумевает контроль со стороны мастера, помимо пройденного пользователем инструктажа.</p>',25)),l(t,{link:"https://www.youtube.com/watch?v=ievafBILu-s"}),a[3]||(a[3]=i('<p><img src="'+H+'" alt=""><img src="'+W+'" alt=""><img src="'+C+'" alt=""><img src="'+I+'" alt=""></p><p><img src="'+Q+'" alt=""></p>',2))])}const Z=r(V,[["render",M]]);export{O as __pageData,Z as default};
